module top_module(
    input [3:0] in,
    output reg [3:0] out
);// Invert all bits of "in"
    wire [3:0] unused_inverted = ~in;

    // Add 1 to the unused_inverted value
    wire [3:0] added = unused_inverted + 1;

    // Output the resulting value as "out"
    assign out = added;

endmodule
